using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _service = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        // Drain the static ConcurrentQueue to prevent cross-test leakage
        var drainService = new NotificationService();
        while (drainService.ReceiveNotification() != null) { }
        drainService.Dispose();

        _service = new NotificationService();
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _service.Dispose();
    }

    // ---- SendNotification (4-param overload) ----

    [TestMethod]
    public void SendNotification_WithCreateOperation_EnqueuesNotificationWithCorrectMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "42", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
        Assert.AreEqual("System", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithUserName_SetsCreatedByToUserName()
    {
        // Arrange & Act
        _service.SendNotification("Course", "101", EntityOperation.UPDATE, "admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("admin", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithNullUserName_SetsCreatedByToSystem()
    {
        // Arrange & Act
        _service.SendNotification("Course", "101", EntityOperation.UPDATE, null);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsCreatedByToSystem()
    {
        // Arrange & Act
        _service.SendNotification("Course", "101", EntityOperation.DELETE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    // ---- SendNotification (5-param overload with entityDisplayName) ----

