        var items = new List<string> { "a", "b" };

        // Act
        var list = new PaginatedList<string>(items, 10, 2, 5);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    public void Constructor_CalculatesTotalPagesCorrectly()
    {
        // Arrange & Act  (10 items / 3 per page = ceil(3.33) = 4)
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 3);

        // Assert
        Assert.AreEqual(4, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_TotalPages_ExactDivision()
    {
        // Arrange & Act  (10 items / 5 per page = ceil(2.0) = 2)
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        // Assert
        Assert.AreEqual(2, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_TotalPages_SingleItem()
    {
        // Arrange & Act (1 item / 5 per page = ceil(0.2) = 1)
        var list = new PaginatedList<int>(new List<int>(), 1, 1, 5);

        // Assert
        Assert.AreEqual(1, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_TotalPages_ZeroItems()
    {
        // Arrange & Act (0 items / 5 per page = ceil(0) = 0)
        var list = new PaginatedList<int>(new List<int>(), 0, 1, 5);

        // Assert
        Assert.AreEqual(0, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<string> { "alpha", "beta", "gamma" };

        // Act
        var list = new PaginatedList<string>(items, 20, 1, 5);

        // Assert
        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("alpha", list[0]);
        Assert.AreEqual("beta", list[1]);
        Assert.AreEqual("gamma", list[2]);
    }

    [TestMethod]
    public void Constructor_EmptyItems_ResultsInEmptyList()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);

        // Assert
        Assert.AreEqual(0, list.Count);
    }

    // ---- HasPreviousPage ----

    [TestMethod]
    public void HasPreviousPage_PageIndexOne_ReturnsFalse()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        // Assert
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_PageIndexTwo_ReturnsTrue()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

        // Assert
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_PageIndexGreaterThanTwo_ReturnsTrue()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), 100, 5, 10);

        // Assert
        Assert.IsTrue(list.HasPreviousPage);
    }

    // ---- HasNextPage ----

    [TestMethod]
    public void HasNextPage_OnLastPage_ReturnsFalse()
    {
        // Arrange & Act (10 items / 5 per page = 2 pages; pageIndex=2)
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

        // Assert
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_BeforeLastPage_ReturnsTrue()
    {
        // Arrange & Act (10 items / 5 per page = 2 pages; pageIndex=1)
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        // Assert
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_OnlyOnePage_ReturnsFalse()
    {
        // Arrange & Act (3 items / 5 per page = 1 page; pageIndex=1)
        var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);

        // Assert
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_ZeroItems_ReturnsFalse()
    {
        // Arrange & Act (0 items / 5 per page = 0 pages; pageIndex=1)
        // PageIndex(1) < TotalPages(0) => false
        var list = new PaginatedList<int>(new List<int>(), 0, 1, 5);

        // Assert
        Assert.IsFalse(list.HasNextPage);
    }

    // ---- Create (static factory from IQueryable) ----

    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages); // 20/5 = 4
    }

    [TestMethod]
    public void Create_MiddlePage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);  // Skip(5).Take(5) => 6,7,8,9,10
        Assert.AreEqual(10, result[4]);
        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange (7 items, pageSize 3 => pages: [1,2,3], [4,5,6], [7])
        var source = Enumerable.Range(1, 7).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 3);

        // Assert
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(7, result[0]);
        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages); // ceil(7/3) = 3
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = new List<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(0, result.TotalPages);
    }

    [TestMethod]
    public void Create_PageSizeEqualsCount_ReturnsSinglePage()
    {
        // Arrange
        var source = Enumerable.Range(1, 5).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_PageSizeOfOne_CorrectPagination()
    {
        // Arrange
        var source = new List<string> { "a", "b", "c" }.AsQueryable();

        // Act
        var result = PaginatedList<string>.Create(source, 2, 1);

        // Assert
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual("b", result[0]);
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.IsTrue(result.HasPreviousPage);
        Assert.IsTrue(result.HasNextPage);
    }

    // ---- Combined property checks ----

    [TestMethod]
    [DataRow(1, false, true)]   // first page
    [DataRow(2, true, true)]    // middle page
    [DataRow(4, true, false)]   // last page
    public void Create_PaginationProperties_CorrectForPosition(
        int pageIndex, bool expectedHasPrevious, bool expectedHasNext)
    {
        // Arrange (20 items, pageSize 5 => 4 pages)
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex, 5);

        // Assert
        Assert.AreEqual(expectedHasPrevious, result.HasPreviousPage);
        Assert.AreEqual(expectedHasNext, result.HasNextPage);
    }
}

