using System.ComponentModel.DataAnnotations;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class StudentTests
{
    // ---- Inheritance from Person ----

    [TestMethod]
    public void Student_IsSubclassOfPerson()
    {
        // Arrange & Act
        var student = new Student();

        // Assert
        Assert.IsInstanceOfType<Person>(student);
    }

    [TestMethod]
    public void FullName_OnStudentInstance_ReturnsLastNameCommaFirstMidName()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Doe",
            FirstMidName = "Jane",
            EnrollmentDate = DateTime.Today
        };

        // Act
        var fullName = student.FullName;

        // Assert
        Assert.AreEqual("Doe, Jane", fullName);
    }

    [TestMethod]
    public void ID_CanBeSetOnStudent()
    {
        // Arrange & Act
        var student = new Student { ID = 99 };

        // Assert
        Assert.AreEqual(99, student.ID);
    }

    // ---- EnrollmentDate property ----

    [TestMethod]
    public void EnrollmentDate_CanBeSetAndRetrieved()
    {
        // Arrange
        var date = new DateTime(2024, 1, 15);
        var student = new Student { EnrollmentDate = date };

        // Act & Assert
        Assert.AreEqual(date, student.EnrollmentDate);
    }

    [TestMethod]
    public void EnrollmentDate_DefaultsToDateTimeMinValue()
    {
        // Arrange & Act
        var student = new Student();

        // Assert
        Assert.AreEqual(default(DateTime), student.EnrollmentDate);
    }

    // ---- EnrollmentDate validation ----

    [TestMethod]
    public void Validation_ValidEnrollmentDate_Succeeds()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "John",
            EnrollmentDate = new DateTime(2024, 1, 15)
        };
        var context = new ValidationContext(student);
        var results = new List<ValidationResult>();

        // Act
        var isValid = Validator.TryValidateObject(student, context, results, true);

        // Assert
        Assert.IsTrue(isValid);
        Assert.AreEqual(0, results.Count);
    }

    [TestMethod]
    public void Validation_EnrollmentDateAtMinBoundary_Succeeds()
    {
        // Arrange — Range lower bound is 1/1/1753
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "John",
            EnrollmentDate = new DateTime(1753, 1, 1)
        };
        var context = new ValidationContext(student);
        var results = new List<ValidationResult>();

        // Act
        var isValid = Validator.TryValidateObject(student, context, results, true);

        // Assert
        Assert.IsTrue(isValid);
    }

    [TestMethod]
    public void Validation_EnrollmentDateAtMaxBoundary_Succeeds()
    {
        // Arrange — Range upper bound is 12/31/9999
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "John",
            EnrollmentDate = new DateTime(9999, 12, 31)
        };
        var context = new ValidationContext(student);
        var results = new List<ValidationResult>();

        // Act
        var isValid = Validator.TryValidateObject(student, context, results, true);

        // Assert
        Assert.IsTrue(isValid);
    }

    [TestMethod]
    public void Validation_EnrollmentDateDefaultValue_FailsRange()
    {
        // Arrange — default(DateTime) = 01/01/0001 which is before 1/1/1753
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "John",
            EnrollmentDate = default
        };
        var context = new ValidationContext(student);
        var results = new List<ValidationResult>();

        // Act
        var isValid = Validator.TryValidateObject(student, context, results, true);

        // Assert
        Assert.IsFalse(isValid);
        Assert.IsTrue(results.Any(r => r.MemberNames.Contains("EnrollmentDate")));
    }

    [TestMethod]
    public void Validation_EnrollmentDateRangeError_HasCustomErrorMessage()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "John",
            EnrollmentDate = default
        };
        var context = new ValidationContext(student);
        var results = new List<ValidationResult>();

        // Act
        Validator.TryValidateObject(student, context, results, true);

        // Assert
        var enrollmentError = results.First(r => r.MemberNames.Contains("EnrollmentDate"));
        Assert.AreEqual("Enrollment date must be between 1753 and 9999", enrollmentError.ErrorMessage);
    }

    // ---- Enrollments navigation property ----

    [TestMethod]
    public void Enrollments_DefaultsToNull()
    {
        // Arrange & Act
        var student = new Student();

        // Assert
        Assert.IsNull(student.Enrollments);
    }

    [TestMethod]
    public void Enrollments_CanBeSetToEmptyList()
    {
        // Arrange
        var student = new Student
        {
            Enrollments = new List<Enrollment>()
        };

        // Act & Assert
        Assert.IsNotNull(student.Enrollments);
        Assert.AreEqual(0, student.Enrollments.Count);
    }

    [TestMethod]
    public void Enrollments_CanBeSetToPopulatedList()
    {
        // Arrange
        var enrollment1 = new Enrollment { EnrollmentID = 1, CourseID = 101 };
        var enrollment2 = new Enrollment { EnrollmentID = 2, CourseID = 102 };
        var student = new Student
        {
            Enrollments = new List<Enrollment> { enrollment1, enrollment2 }
        };

        // Act & Assert
        Assert.AreEqual(2, student.Enrollments.Count);
    }

    [TestMethod]
    public void Enrollments_CanAddItemsAfterInitialization()
    {
        // Arrange
        var student = new Student
        {
            Enrollments = new List<Enrollment>()
        };

        // Act
        student.Enrollments.Add(new Enrollment { EnrollmentID = 1 });

        // Assert
        Assert.AreEqual(1, student.Enrollments.Count);
    }
}

