using System;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext($"StudentsDb_{Guid.NewGuid()}");
        _controller = new StudentsController(_context);
        // TempData is needed for DeleteConfirmed error path
        _controller.TempData = new TempDataDictionary(
            new DefaultHttpContext(),
            Mock.Of<ITempDataProvider>());
        DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
        DrainNotificationQueue();
    }

    private static void DrainNotificationQueue()
    {
        using var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    private void SeedStudents(params (string lastName, string firstName, DateTime enrollmentDate)[] students)
    {
        foreach (var (lastName, firstName, enrollmentDate) in students)
        {
            _context.Students.Add(new Student
            {
                LastName = lastName,
                FirstMidName = firstName,
                EnrollmentDate = enrollmentDate
            });
        }
        _context.SaveChanges();
    }

    private void SeedDefaultStudents()
    {
        SeedStudents(
            ("Alexander", "Carson", new DateTime(2020, 9, 1)),
            ("Alonso", "Meredith", new DateTime(2019, 9, 1)),
            ("Anand", "Arturo", new DateTime(2021, 9, 1)),
            ("Barzdukas", "Gytis", new DateTime(2018, 9, 1)),
            ("Li", "Yan", new DateTime(2022, 9, 1))
        );
    }

    // ========== Index: Sorting ==========

    [TestMethod]
    public void Index_NoParams_ReturnsStudentsOrderedByLastNameAscending()
    {
        SeedDefaultStudents();

        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(5, model!.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Anand", model[2].LastName);
        Assert.AreEqual("Barzdukas", model[3].LastName);
        Assert.AreEqual("Li", model[4].LastName);
    }

    [TestMethod]
    public void Index_SortOrderNameDesc_ReturnsStudentsOrderedByLastNameDescending()
    {
        SeedDefaultStudents();

        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Li", model![0].LastName);
        Assert.AreEqual("Barzdukas", model[1].LastName);
        Assert.AreEqual("Anand", model[2].LastName);
        Assert.AreEqual("Alonso", model[3].LastName);
        Assert.AreEqual("Alexander", model[4].LastName);
    }

    [TestMethod]
    public void Index_SortOrderDate_ReturnsStudentsOrderedByEnrollmentDateAscending()
    {
        SeedStudents(
            ("Alpha", "A", new DateTime(2021, 1, 1)),
            ("Beta", "B", new DateTime(2019, 1, 1)),
            ("Gamma", "C", new DateTime(2020, 1, 1))
        );

        var result = _controller.Index("Date", null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Beta", model![0].LastName);
        Assert.AreEqual("Gamma", model[1].LastName);
        Assert.AreEqual("Alpha", model[2].LastName);
    }

    [TestMethod]
    public void Index_SortOrderDateDesc_ReturnsStudentsOrderedByEnrollmentDateDescending()
    {
        SeedStudents(
            ("Alpha", "A", new DateTime(2021, 1, 1)),
            ("Beta", "B", new DateTime(2019, 1, 1)),
            ("Gamma", "C", new DateTime(2020, 1, 1))
        );

        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alpha", model![0].LastName);
        Assert.AreEqual("Gamma", model[1].LastName);
        Assert.AreEqual("Beta", model[2].LastName);
    }

    [TestMethod]
    public void Index_UnknownSortOrder_DefaultsToLastNameAscending()
    {
        SeedDefaultStudents();

        var result = _controller.Index("unknown_value", null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model![0].LastName);
        Assert.AreEqual("Li", model[4].LastName);
    }

    // ========== Index: Filtering ==========

    [TestMethod]
    public void Index_SearchString_FiltersStudentsByLastName()
    {
        SeedDefaultStudents();

        var result = _controller.Index(null, null, "Li", null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual("Li", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchString_FiltersStudentsByFirstMidName()
    {
        SeedDefaultStudents();

        var result = _controller.Index(null, null, "Carson", null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
        Assert.AreEqual("Carson", model[0].FirstMidName);
    }

    [TestMethod]
    public void Index_NullSearchString_ReturnsAllStudents()
    {
        SeedDefaultStudents();

        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(5, model!.Count);
    }

    [TestMethod]
    public void Index_NewSearch_ResetsPageToOne()
    {
        // Seed 15 students for multiple pages (pageSize = 10)
        for (int i = 0; i < 15; i++)
        {
            _context.Students.Add(new Student
            {
                LastName = $"Student{i:D2}",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2020, 1, 1)
            });
        }
        _context.SaveChanges();

        // searchString is non-null → page is reset to 1, even if page param says 2
        var result = _controller.Index(null, null, "Student", 2) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model!.PageIndex);
    }

    [TestMethod]
    public void Index_CurrentFilterPreserved_WhenNoNewSearch()
    {
        SeedDefaultStudents();

        // searchString is null → currentFilter is used as searchString
        var result = _controller.Index(null, "Li", null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual("Li", model[0].LastName);
        Assert.AreEqual("Li", _controller.ViewData["CurrentFilter"]);
    }

    // ========== Index: Pagination ==========

    [TestMethod]
    public void Index_Pagination_FirstPageHasNextButNoPrevious()
    {
        // Seed 15 students → pageSize=10 → 2 pages
        for (int i = 0; i < 15; i++)
        {
            _context.Students.Add(new Student
            {
                LastName = $"S{i:D2}",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2020, 1, 1)
            });
        }
        _context.SaveChanges();

        var result = _controller.Index(null, null, null, 1) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(10, model!.Count);
        Assert.AreEqual(1, model.PageIndex);
        Assert.IsFalse(model.HasPreviousPage);
        Assert.IsTrue(model.HasNextPage);
    }

    [TestMethod]
    public void Index_Pagination_LastPageHasPreviousButNoNext()
    {
        for (int i = 0; i < 15; i++)
        {
            _context.Students.Add(new Student
            {
                LastName = $"S{i:D2}",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2020, 1, 1)
            });
        }
        _context.SaveChanges();

        var result = _controller.Index(null, null, null, 2) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(5, model!.Count);
        Assert.AreEqual(2, model.PageIndex);
        Assert.IsTrue(model.HasPreviousPage);
        Assert.IsFalse(model.HasNextPage);
    }

    [TestMethod]
    public void Index_NullPage_DefaultsToPageOne()
    {
        SeedDefaultStudents();

        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model!.PageIndex);
    }

    // ========== Index: ViewBag / ViewData ==========

    [TestMethod]
    public void Index_ViewBag_SetsCurrentSortToSortOrder()
    {
        SeedDefaultStudents();

        _controller.Index("name_desc", null, null, null);

        Assert.AreEqual("name_desc", _controller.ViewData["CurrentSort"]);
    }

    [TestMethod]
    [DataRow(null, "name_desc")]
    [DataRow("", "name_desc")]
    [DataRow("name_desc", "")]
    [DataRow("Date", "")]
    public void Index_ViewBag_SetsNameSortParmCorrectly(string? sortOrder, string expectedNameSortParm)
    {
        SeedDefaultStudents();

        _controller.Index(sortOrder, null, null, null);

        Assert.AreEqual(expectedNameSortParm, _controller.ViewData["NameSortParm"]);
    }

    [TestMethod]
    [DataRow("Date", "date_desc")]
    [DataRow(null, "Date")]
    [DataRow("name_desc", "Date")]
    [DataRow("date_desc", "Date")]
    public void Index_ViewBag_SetsDateSortParmCorrectly(string? sortOrder, string expectedDateSortParm)
    {
        SeedDefaultStudents();

        _controller.Index(sortOrder, null, null, null);

        Assert.AreEqual(expectedDateSortParm, _controller.ViewData["DateSortParm"]);
    }

    [TestMethod]
    public void Index_ViewBag_SetsCurrentFilterToSearchString()
    {
        SeedDefaultStudents();

        _controller.Index(null, null, "test_filter", null);

        Assert.AreEqual("test_filter", _controller.ViewData["CurrentFilter"]);
    }

    [TestMethod]
    public void Index_CombinedSortAndFilter_WorksTogether()
    {
        SeedDefaultStudents();
        // "Al" matches Alexander, Alonso, and Anand (but Anand has no "Al")
        // Actually: "Al" in LastName → Alexander, Alonso. "Al" in FirstMidName → none of them start with "Al".
        // Wait: Contains("Al") checks: Alexander contains "Al"? Yes (case-sensitive in InMemory).
        // InMemory is case-sensitive by default: "Alexander".Contains("Al") → true, "Alonso".Contains("Al") → true
        // "Anand".Contains("Al") → false
        // FirstMidName: "Carson".Contains("Al") → false, "Meredith".Contains("Al") → false, etc.
        // So "Al" matches Alexander and Alonso by LastName

        var result = _controller.Index("name_desc", null, "Al", null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model!.Count);
        // name_desc → descending by LastName
        Assert.AreEqual("Alonso", model[0].LastName);
        Assert.AreEqual("Alexander", model[1].LastName);
    }

    // ========== Details ==========

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        SeedDefaultStudents();
        var student = _context.Students.First();

        var result = _controller.Details(student.ID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model!.ID);
        Assert.AreEqual(student.LastName, model.LastName);
        Assert.AreEqual(student.FirstMidName, model.FirstMidName);
    }

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result!.StatusCode);
    }

    [TestMethod]
    public void Details_NonexistentId_ThrowsInvalidOperationException()
    {
        // The controller uses .Single() which throws when no element is found
        Assert.ThrowsException<InvalidOperationException>(() => _controller.Details(999));
    }

    // ========== Create GET ==========

    [TestMethod]
    public void Create_Get_ReturnsViewWithStudentAndTodaysDate()
    {
        var result = _controller.Create() as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model!.EnrollmentDate);
    }

    // ========== Create POST ==========

    [TestMethod]
    public void Create_Post_ValidStudent_SavesAndRedirectsToIndex()
    {
        var student = new Student
        {
            LastName = "TestLast",
            FirstMidName = "TestFirst",
            EnrollmentDate = new DateTime(2024, 1, 15)
        };

        var result = _controller.Create(student) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result!.ActionName);
        Assert.AreEqual(1, _context.Students.Count());
        var saved = _context.Students.First();
        Assert.AreEqual("TestLast", saved.LastName);
        Assert.AreEqual("TestFirst", saved.FirstMidName);
        Assert.AreEqual(new DateTime(2024, 1, 15), saved.EnrollmentDate);
    }

    [TestMethod]
    public void Create_Post_ValidStudent_SendsCreateNotification()
    {
        DrainNotificationQueue();
        var student = new Student
        {
            LastName = "Doe",
            FirstMidName = "John",
            EnrollmentDate = new DateTime(2024, 1, 15)
        };

        _controller.Create(student);

        using var svc = new NotificationService();
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification!.EntityType);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.IsTrue(notification.Message.Contains("created"));
        Assert.IsTrue(notification.Message.Contains("John Doe"));
    }

    [TestMethod]
    public void Create_Post_MinValueEnrollmentDate_ReturnsViewWithModelError()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsFalse(_controller.ModelState.IsValid);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
        Assert.AreEqual(0, _context.Students.Count());
    }

    [TestMethod]
    public void Create_Post_DateBefore1753_ReturnsViewWithRangeError()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsFalse(_controller.ModelState.IsValid);
        Assert.IsTrue(_controller.ModelState["EnrollmentDate"]!.Errors
            .Any(e => e.ErrorMessage.Contains("1753")));
        Assert.AreEqual(0, _context.Students.Count());
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsViewWithStudent()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(2024, 1, 15)
        };
        _controller.ModelState.AddModelError("LastName", "Some error");

        var result = _controller.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Test", model!.LastName);
        Assert.AreEqual(0, _context.Students.Count());
    }

    // ========== Edit GET ==========

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        SeedDefaultStudents();
        var student = _context.Students.First();

        var result = _controller.Edit(student.ID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model!.ID);
        Assert.AreEqual(student.LastName, model.LastName);
    }

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result!.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_NonexistentId_ReturnsNotFound()
    {
        var result = _controller.Edit(999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    // ========== Edit POST ==========

    [TestMethod]
    public void Edit_Post_ValidStudent_UpdatesAndRedirectsToIndex()
    {
        SeedDefaultStudents();
        var original = _context.Students.First();
        var originalId = original.ID;
        // Detach so the controller can attach the modified version
        _context.Entry(original).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updated = new Student
        {
            ID = originalId,
            LastName = "UpdatedLast",
            FirstMidName = "UpdatedFirst",
            EnrollmentDate = new DateTime(2024, 6, 1)
        };

        var result = _controller.Edit(updated) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result!.ActionName);

        // Verify update was persisted
        var fromDb = _context.Students.Find(originalId);
        Assert.IsNotNull(fromDb);
        Assert.AreEqual("UpdatedLast", fromDb!.LastName);
        Assert.AreEqual("UpdatedFirst", fromDb.FirstMidName);
    }

    [TestMethod]
    public void Edit_Post_ValidStudent_SendsUpdateNotification()
    {
        DrainNotificationQueue();
        SeedDefaultStudents();
        var original = _context.Students.First();
        var originalId = original.ID;
        _context.Entry(original).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updated = new Student
        {
            ID = originalId,
            LastName = "UpdatedLast",
            FirstMidName = "UpdatedFirst",
            EnrollmentDate = new DateTime(2024, 6, 1)
        };

        _controller.Edit(updated);

        using var svc = new NotificationService();
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification!.EntityType);
        Assert.AreEqual("UPDATE", notification.Operation);
        Assert.IsTrue(notification.Message.Contains("updated"));
    }

    [TestMethod]
    public void Edit_Post_MinValueEnrollmentDate_ReturnsViewWithError()
    {
        var student = new Student
        {
            ID = 1,
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Edit(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsFalse(_controller.ModelState.IsValid);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Edit_Post_InvalidModelState_ReturnsViewWithStudent()
    {
        var student = new Student
        {
            ID = 1,
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(2024, 1, 15)
        };
        _controller.ModelState.AddModelError("LastName", "Some error");

        var result = _controller.Edit(student) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Test", model!.LastName);
    }

    // ========== Delete GET ==========

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithStudent()
    {
        SeedDefaultStudents();
        var student = _context.Students.First();

        var result = _controller.Delete(student.ID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model!.ID);
        Assert.AreEqual(student.LastName, model.LastName);
    }

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
