using System;
using System.IO;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Logging.Abstractions;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext _context = null!;
    private CoursesController _controller = null!;
    private Mock<IWebHostEnvironment> _mockEnv = null!;
    private string _tempWebRoot = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext($"CoursesDb_{Guid.NewGuid()}");
        _tempWebRoot = Path.Combine(Path.GetTempPath(), $"CoursesTest_{Guid.NewGuid()}");
        Directory.CreateDirectory(_tempWebRoot);
        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockEnv.Setup(e => e.WebRootPath).Returns(_tempWebRoot);
        var logger = new NullLogger<CoursesController>();
        _controller = new CoursesController(_context, _mockEnv.Object, logger);

        // Seed a department for FK references
        _context.Departments.Add(new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 100000,
            StartDate = new DateTime(2020, 1, 1)
        });
        _context.SaveChanges();
        DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
        if (Directory.Exists(_tempWebRoot))
            Directory.Delete(_tempWebRoot, true);
        DrainNotificationQueue();
    }

    private static void DrainNotificationQueue()
    {
        using var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    private Course SeedCourse(int courseId = 1001, string title = "Calculus", int credits = 3, int departmentId = 1, string? imagePath = null)
    {
        var course = new Course
        {
            CourseID = courseId,
            Title = title,
            Credits = credits,
            DepartmentID = departmentId,
            TeachingMaterialImagePath = imagePath!
        };
        _context.Courses.Add(course);
        _context.SaveChanges();
        return course;
    }

    private static Mock<IFormFile> CreateMockFile(string fileName, long length)
    {
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns(fileName);
        mockFile.Setup(f => f.Length).Returns(length);
        mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => { /* no-op */ });
        return mockFile;
    }

    // ========== Index ==========

    [TestMethod]
    public void Index_ReturnsViewWithAllCourses()
    {
        SeedCourse(1001, "Calculus", 3);
        SeedCourse(1002, "Chemistry", 4);

        var result = _controller.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as System.Collections.Generic.List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model!.Count);
    }

    [TestMethod]
    public void Index_IncludesDepartmentNavigation()
    {
        SeedCourse(1001, "Calculus", 3, 1);

        var result = _controller.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as System.Collections.Generic.List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model!.Count);
        Assert.IsNotNull(model[0].Department);
        Assert.AreEqual("Engineering", model[0].Department.Name);
    }

    [TestMethod]
    public void Index_EmptyDatabase_ReturnsEmptyList()
    {
        var result = _controller.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as System.Collections.Generic.List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model!.Count);
    }

    // ========== Details ==========

    [TestMethod]
