using System;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context = null!;
    private DepartmentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext($"DepartmentsDb_{Guid.NewGuid()}");
        _controller = new DepartmentsController(_context);
        DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
        DrainNotificationQueue();
    }

    private static void DrainNotificationQueue()
    {
        using var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    private Instructor SeedInstructor(string lastName = "Fakhouri", string firstName = "Fadi", int? id = null)
    {
        var instructor = new Instructor
        {
            LastName = lastName,
            FirstMidName = firstName,
            HireDate = new DateTime(2002, 7, 6)
        };
        if (id.HasValue) instructor.ID = id.Value;
        _context.Instructors.Add(instructor);
        _context.SaveChanges();
        return instructor;
    }

    private Department SeedDepartment(string name = "Engineering", decimal budget = 350000m,
        int? instructorId = null, int? departmentId = null)
    {
        var dept = new Department
        {
            Name = name,
            Budget = budget,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = instructorId
        };
        if (departmentId.HasValue) dept.DepartmentID = departmentId.Value;
        _context.Departments.Add(dept);
        _context.SaveChanges();
        return dept;
    }

    // ========== Index ==========

    [TestMethod]
    public void Index_ReturnsViewWithAllDepartments()
    {
        SeedDepartment("Engineering", 350000m);
        SeedDepartment("Mathematics", 100000m);

        var result = _controller.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as System.Collections.Generic.List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model!.Count);
    }

    [TestMethod]
    public void Index_EmptyDatabase_ReturnsEmptyList()
    {
        var result = _controller.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as System.Collections.Generic.List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model!.Count);
    }

    [TestMethod]
    public void Index_IncludesAdministratorNavigation()
    {
        var instructor = SeedInstructor("Kapoor", "Candace");
        SeedDepartment("Engineering", 350000m, instructor.ID);

        var result = _controller.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as System.Collections.Generic.List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model!.Count);
        Assert.IsNotNull(model[0].Administrator);
        Assert.AreEqual("Kapoor", model[0].Administrator.LastName);
        Assert.AreEqual("Candace", model[0].Administrator.FirstMidName);
    }

    [TestMethod]
    public void Index_DepartmentWithNullAdministrator_ReturnsNullAdministrator()
    {
        SeedDepartment("English", 100000m, instructorId: null);

        var result = _controller.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as System.Collections.Generic.List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model!.Count);
        Assert.IsNull(model[0].Administrator);
    }

    // ========== Details ==========

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        var dept = SeedDepartment("Engineering", 350000m);

        var result = _controller.Details(dept.DepartmentID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual(dept.DepartmentID, model!.DepartmentID);
        Assert.AreEqual("Engineering", model.Name);
        Assert.AreEqual(350000m, model.Budget);
    }

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result!.StatusCode);
    }

    [TestMethod]
    public void Details_NonexistentId_ReturnsNotFound()
    {
        var result = _controller.Details(999) as NotFoundResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(404, result!.StatusCode);
    }

    // ========== Create GET ==========

    [TestMethod]
    public void Create_Get_ReturnsView()
    {
        var result = _controller.Create() as ViewResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Create_Get_PopulatesInstructorIdSelectList()
    {
        SeedInstructor("Fakhouri", "Fadi");
        SeedInstructor("Harui", "Roger");

        var result = _controller.Create() as ViewResult;

        Assert.IsNotNull(result);
        var selectList = _controller.ViewBag.InstructorID as SelectList;
        Assert.IsNotNull(selectList);
        Assert.AreEqual(2, selectList!.Count());
    }

    [TestMethod]
    public void Create_Get_EmptyInstructors_ReturnsEmptySelectList()
    {
        var result = _controller.Create() as ViewResult;

        Assert.IsNotNull(result);
        var selectList = _controller.ViewBag.InstructorID as SelectList;
        Assert.IsNotNull(selectList);
        Assert.AreEqual(0, selectList!.Count());
    }

    [TestMethod]
    public void Create_Get_SelectListUsesFullName()
    {
        var instructor = SeedInstructor("Kapoor", "Candace");

        _controller.Create();

        var selectList = _controller.ViewBag.InstructorID as SelectList;
        Assert.IsNotNull(selectList);
        var item = selectList!.First();
        // FullName is "LastName, FirstMidName"
        Assert.AreEqual("Kapoor, Candace", item.Text);
    }

    // ========== Create POST ==========

    [TestMethod]
    public void Create_Post_ValidDepartment_SavesAndRedirectsToIndex()
    {
        var instructor = SeedInstructor();
        var dept = new Department
        {
            Name = "Biology",
            Budget = 200000m,
            StartDate = new DateTime(2010, 9, 1),
            InstructorID = instructor.ID
        };

        var result = _controller.Create(dept) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result!.ActionName);
        Assert.AreEqual(1, _context.Departments.Count());
        var saved = _context.Departments.First();
        Assert.AreEqual("Biology", saved.Name);
        Assert.AreEqual(200000m, saved.Budget);
    }

    [TestMethod]
    public void Create_Post_ValidDepartment_SendsCreateNotification()
    {
        var dept = new Department
        {
            Name = "Biology",
            Budget = 200000m,
            StartDate = new DateTime(2010, 9, 1)
        };

        _controller.Create(dept);

        using var svc = new NotificationService();
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Department", notification!.EntityType);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.IsTrue(notification.Message.Contains("Biology"));
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsViewWithDepartment()
    {
        var instructor = SeedInstructor();
        var dept = new Department
        {
            Name = "Biology",
            Budget = 200000m,
            StartDate = new DateTime(2010, 9, 1),
            InstructorID = instructor.ID
        };
        _controller.ModelState.AddModelError("Name", "Name is required");

        var result = _controller.Create(dept) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual("Biology", model!.Name);
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_PopulatesInstructorIdSelectList()
    {
        var instructor = SeedInstructor("Fakhouri", "Fadi");
        var dept = new Department
        {
            Name = "Biology",
            Budget = 200000m,
            StartDate = new DateTime(2010, 9, 1),
            InstructorID = instructor.ID
        };
        _controller.ModelState.AddModelError("Name", "Name is required");

        _controller.Create(dept);

        var selectList = _controller.ViewBag.InstructorID as SelectList;
        Assert.IsNotNull(selectList);
        Assert.AreEqual(1, selectList!.Count());
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_DoesNotSaveDepartment()
    {
        var dept = new Department
        {
            Name = "Biology",
            Budget = 200000m,
            StartDate = new DateTime(2010, 9, 1)
        };
        _controller.ModelState.AddModelError("Name", "Name is required");

        _controller.Create(dept);

        Assert.AreEqual(0, _context.Departments.Count());
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_SelectListPreselectsInstructorId()
    {
        var instructor = SeedInstructor("Zheng", "Roger");
        var dept = new Department
        {
            Name = "Bio",
            Budget = 200000m,
            StartDate = new DateTime(2010, 9, 1),
            InstructorID = instructor.ID
        };
        _controller.ModelState.AddModelError("Budget", "Invalid");

        _controller.Create(dept);

        var selectList = _controller.ViewBag.InstructorID as SelectList;
        Assert.IsNotNull(selectList);
        // The 4th parameter to new SelectList(..., department.InstructorID) sets SelectedValue
        Assert.AreEqual(instructor.ID.ToString(), selectList!.SelectedValue?.ToString());
    }

    // ========== Edit GET ==========

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithDepartment()
    {
        var dept = SeedDepartment("Engineering", 350000m);

        var result = _controller.Edit(dept.DepartmentID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result!.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual(dept.DepartmentID, model!.DepartmentID);
        Assert.AreEqual("Engineering", model.Name);
        Assert.AreEqual(350000m, model.Budget);
    }

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result!.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_NonexistentId_ReturnsNotFound()
    {
        var result = _controller.Edit(999) as NotFoundResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(404, result!.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_PopulatesInstructorIdSelectList()
    {
        var instructor = SeedInstructor("Fakhouri", "Fadi");
        var dept = SeedDepartment("Engineering", 350000m, instructor.ID);

        _controller.Edit(dept.DepartmentID);

        var selectList = _controller.ViewBag.InstructorID as SelectList;
        Assert.IsNotNull(selectList);
        Assert.AreEqual(1, selectList!.Count());
    }

    [TestMethod]
